    while (!unvisitedNodes.isEmpty()) {
        Node node = getNodeWithMinDistance(unvisitedNodes);
        int distance = unvisitedNodes.get(node);
        unvisitedNodes.remove(node);
        if (node.getValue() == goalnode.getValue()) {
            return distance;
